package com.formfiller.ui

import android.content.Intent
import android.os.Build
import android.os.Bundle
import android.provider.Settings
import android.view.autofill.AutofillManager
import android.view.inputmethod.InputMethodManager
import android.widget.*
import androidx.appcompat.app.AlertDialog
import androidx.appcompat.app.AppCompatActivity
import androidx.lifecycle.lifecycleScope
import androidx.recyclerview.widget.LinearLayoutManager
import androidx.recyclerview.widget.RecyclerView
import com.formfiller.R
import com.formfiller.data.AppDatabase
import com.formfiller.data.Field
import com.formfiller.data.Profile
import com.formfiller.ime.FieldExtractor
import kotlinx.coroutines.launch

class MainActivity : AppCompatActivity() {

    private lateinit var db: AppDatabase
    private lateinit var spProfile: Spinner
    private lateinit var rvFields: RecyclerView
    private lateinit var etInput: EditText
    private lateinit var etLabel: EditText
    private lateinit var etValue: EditText

    private var profiles = mutableListOf<Profile>()
    private var fields = mutableListOf<Field>()
    private val currentProfileId get() = profiles.getOrNull(spProfile.selectedItemPosition)?.id

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_main)

        db = AppDatabase.get(this)
        spProfile = findViewById(R.id.spProfile)
        rvFields = findViewById(R.id.rvFields)
        etInput = findViewById(R.id.etInput)
        etLabel = findViewById(R.id.etLabel)
        etValue = findViewById(R.id.etValue)

        rvFields.layoutManager = LinearLayoutManager(this)

        findViewById<Button>(R.id.btnEnableIME).setOnClickListener { enableIME() }
        findViewById<Button>(R.id.btnEnableAutofill).setOnClickListener { enableAutofill() }
        findViewById<ImageButton>(R.id.btnAddProfile).setOnClickListener { addProfile() }
        findViewById<ImageButton>(R.id.btnDeleteProfile).setOnClickListener { deleteProfile() }
        findViewById<Button>(R.id.btnExtract).setOnClickListener { extractFields() }
        findViewById<Button>(R.id.btnAdd).setOnClickListener { addField() }

        spProfile.onItemSelectedListener = object : AdapterView.OnItemSelectedListener {
            override fun onItemSelected(p: AdapterView<*>?, v: android.view.View?, pos: Int, id: Long) = loadFields()
            override fun onNothingSelected(p: AdapterView<*>?) {}
        }

        loadProfiles()
    }

    private fun enableIME() {
        val imm = getSystemService(INPUT_METHOD_SERVICE) as InputMethodManager
        val enabled = imm.enabledInputMethodList.any { it.packageName == packageName }
        if (!enabled) {
            startActivity(Intent(Settings.ACTION_INPUT_METHOD_SETTINGS))
            Toast.makeText(this, "请在设置中启用「智能填表输入法」", Toast.LENGTH_LONG).show()
        } else {
            imm.showInputMethodPicker()
        }
    }

    private fun enableAutofill() {
        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {
            val afm = getSystemService(AutofillManager::class.java)
            if (afm.hasEnabledAutofillServices()) {
                Toast.makeText(this, "自动填充服务已启用", Toast.LENGTH_SHORT).show()
            } else {
                val intent = Intent(Settings.ACTION_REQUEST_SET_AUTOFILL_SERVICE).apply {
                    data = android.net.Uri.parse("package:$packageName")
                }
                startActivity(intent)
                Toast.makeText(this, "请选择「智能填表自动填充」", Toast.LENGTH_LONG).show()
            }
        } else {
            Toast.makeText(this, "自动填充需要 Android 8.0 以上", Toast.LENGTH_SHORT).show()
        }
    }

    private fun loadProfiles() {
        lifecycleScope.launch {
            profiles.clear()
            profiles.addAll(db.profileDao().getAll())
            if (profiles.isEmpty()) {
                val id = db.profileDao().insert(Profile(name = "默认档案"))
                profiles.add(Profile(id = id, name = "默认档案"))
            }
            spProfile.adapter = ArrayAdapter(
                this@MainActivity, android.R.layout.simple_spinner_dropdown_item,
                profiles.map { it.name }
            )
            loadFields()
        }
    }

    private fun loadFields() {
        val pid = currentProfileId ?: return
        lifecycleScope.launch {
            fields.clear()
            fields.addAll(db.fieldDao().getByProfile(pid))
            rvFields.adapter = FieldRowAdapter(fields,
                onDelete = { f ->
                    lifecycleScope.launch {
                        db.fieldDao().delete(f)
                        fields.remove(f)
                        rvFields.adapter?.notifyDataSetChanged()
                    }
                }
            )
        }
    }

    private fun addProfile() {
        val et = EditText(this).apply { hint = "档案名称" }
        AlertDialog.Builder(this).setTitle("新建档案").setView(et)
            .setPositiveButton("确定") { _, _ ->
                val name = et.text.toString().trim()
                if (name.isNotEmpty()) {
                    lifecycleScope.launch {
                        db.profileDao().insert(Profile(name = name))
                        loadProfiles()
                    }
                }
            }.show()
    }

    private fun deleteProfile() {
        val p = profiles.getOrNull(spProfile.selectedItemPosition) ?: return
        if (profiles.size <= 1) {
            Toast.makeText(this, "至少保留一个档案", Toast.LENGTH_SHORT).show()
            return
        }
        AlertDialog.Builder(this).setTitle("删除档案「${p.name}」？")
            .setPositiveButton("删除") { _, _ ->
                lifecycleScope.launch {
                    db.profileDao().delete(p)
                    loadProfiles()
                }
            }.setNegativeButton("取消", null).show()
    }

    private fun extractFields() {
        val text = etInput.text.toString().trim()
        if (text.isEmpty()) {
            Toast.makeText(this, "请先输入或粘贴文本", Toast.LENGTH_SHORT).show()
            return
        }
        val pid = currentProfileId ?: return
        val extracted = FieldExtractor.extract(text)
        if (extracted.isEmpty()) {
            Toast.makeText(this, "未提取到字段", Toast.LENGTH_SHORT).show()
            return
        }
        lifecycleScope.launch {
            val newFields = extracted.map { Field(profileId = pid, label = it.label, value = it.value, fieldType = it.type) }
            db.fieldDao().insertAll(newFields)
            loadFields()
            Toast.makeText(this@MainActivity, "提取了 ${newFields.size} 个字段", Toast.LENGTH_SHORT).show()
        }
    }

    private fun addField() {
        val label = etLabel.text.toString().trim()
        val value = etValue.text.toString().trim()
        if (label.isEmpty() || value.isEmpty()) return
        val pid = currentProfileId ?: return
        lifecycleScope.launch {
            db.fieldDao().insert(Field(profileId = pid, label = label, value = value))
            etLabel.text.clear()
            etValue.text.clear()
            loadFields()
        }
    }
}

