    'together': {'name': 'Together AI', 'region': 'intl', 'endpoint': 'https://api.together.xyz/v1/chat/completions', 'default_model': 'meta-llama/Llama-3-70b-chat-hf'},
}

DEFAULT_CONFIG = {
    'asr_provider': 'funasr',  # 默认使用本地FunASR
    'llm_provider': 'zhipu',
    'asr_keys': {},
    'llm_keys': {},
    'font_size': '中',
}

def load_config():
    if os.path.exists(CONFIG_FILE):
        try:
            with open(CONFIG_FILE, 'r', encoding='utf-8') as f:
                return {**DEFAULT_CONFIG, **json.load(f)}
        except Exception:
            pass
    return dict(DEFAULT_CONFIG)

def save_config(config):
    os.makedirs(CONFIG_DIR, exist_ok=True)
    with open(CONFIG_FILE, 'w', encoding='utf-8') as f:
        json.dump(config, f, ensure_ascii=False, indent=2)

def is_valid(config: Dict[str, Any]) -> bool:
    """验证配置是否有效"""
    pid = config.get('asr_provider', '')
    if pid in ('funasr', 'baidu_builtin'):
        return True

    # 检查ASR密钥
    asr_keys = config.get('asr_keys', {}).get(pid, {})
    provider_info = ASR_PROVIDERS.get(pid, {})
    required_fields = provider_info.get('fields', [])

    if required_fields:
        return _validate_keys(asr_keys, required_fields)

    return bool(asr_keys.get('key'))

def get_builtin_keys(provider_id):
    """获取内置API密钥"""
    if provider_id == 'baidu_builtin':
        return BUILTIN_BAIDU_KEYS.copy()
    return {}

