                Toast.makeText(this@MainActivity, "比对失败: ${e.message}", Toast.LENGTH_SHORT).show()
            } finally {
                progressBar.visibility = android.view.View.GONE
            }
        }
    }
}

/**
 * 差异列表适配器
 */
class DiffAdapter(private val diffs: List<TextComparator.DiffItem>) :
    RecyclerView.Adapter<DiffAdapter.DiffViewHolder>() {

    class DiffViewHolder(itemView: android.view.View) : RecyclerView.ViewHolder(itemView) {
        val tvDocText: TextView = itemView.findViewById(R.id.tvDocDiff)
        val tvAudioText: TextView = itemView.findViewById(R.id.tvAudioDiff)
        val tvType: TextView = itemView.findViewById(R.id.tvDiffType)
        val root: android.view.View = itemView.findViewById(R.id.root)
    }

    override fun onCreateViewHolder(parent: android.view.ViewGroup, viewType: Int): DiffViewHolder {
        val view = android.view.LayoutInflater.from(parent.context)
            .inflate(R.layout.item_diff, parent, false)
        return DiffViewHolder(view)
    }

    override fun onBindViewHolder(holder: DiffViewHolder, position: Int) {
        val diff = diffs[position]
        holder.tvDocText.text = diff.docText
        holder.tvAudioText.text = diff.audioText

        val typeText = when (diff.type) {
            TextComparator.DiffType.MISMATCH -> "误读"
            TextComparator.DiffType.MISSING_IN_AUDIO -> "漏读"
            TextComparator.DiffType.EXTRA_IN_AUDIO -> "多读"
        }
        holder.tvType.text = typeText

        // 设置颜色
        val colorRes = when (diff.type) {
            TextComparator.DiffType.MISMATCH -> android.R.color.holo_red_light
            TextComparator.DiffType.MISSING_IN_AUDIO -> android.R.color.holo_orange_light
            TextComparator.DiffType.EXTRA_IN_AUDIO -> android.R.color.holo_blue_light
        }
        holder.root.setBackgroundColor(
            holder.root.context.getColor(colorRes)
        )
    }

    override fun getItemCount() = diffs.size
}

